={{ (() => {
  const text = $('Format Headings').first().json.formatted_content;
  const ranges = $('Format Headings').first().json.heading_ranges;

  const requests = [
    {
      insertText: {
        location: { index: 1 },
        text: text
      }
    }
  ];

  for (const h of ranges) {
    requests.push({
      updateParagraphStyle: {
        range: { startIndex: h.startIndex, endIndex: h.endIndex },
        paragraphStyle: { namedStyleType: 'HEADING_' + h.level },
        fields: 'namedStyleType'
      }
    });
  }

  return JSON.stringify({ requests: requests });
})() }}

