// Read input - use exact sheet column names (capital T)
const html = $json.clean_content || '';
const keyword = $json['Target Keyword'] || $json.keyword || '';
const imageFolderUrl = $json['Image Folder URL'] || $json.image_folder_url || '';
const topic = $json['Topic'] || $json.topic || '';
const rowNumber = $json.row_number;

// Slugify helper
function slugify(s) {
  return (s || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 60);
}

// Extract folder ID
const folderMatch = imageFolderUrl.match(/folders\/([a-zA-Z0-9_-]+)/);
const folderId = folderMatch ? folderMatch[1] : null;

// FEATURED_ALT and FEATURED_LINK are in the metadata, which Parse SEO already stripped.
// Try carried-forward fields first, then any source still available.
const featuredAlt = $json.featured_alt
  || (($json.blog_text || '').match(/FEATURED_ALT:\s*(.+)/) || [])[1]?.trim()
  || (keyword ? keyword + ' overview' : 'article featured image');

const featuredLink = $json.featured_link
  || (($json.blog_text || '').match(/FEATURED_LINK:\s*(.+)/) || [])[1]?.trim()
  || 'https://dimag.agency';

const keywordSlug = slugify(keyword) || 'blog';

// Featured image spec
const specs = [{
  is_featured: true,
  source_filename: 'featured.png',
  seo_filename: keywordSlug + '-featured.png',
  alt_text: featuredAlt,
  link_url: featuredLink,
  position: 0
}];

// Parse inline [[IMAGE_N|alt|link]] placeholders
const inlineRegex = /\[\[IMAGE_(\d+)(?:\|([^\]|]*))?(?:\|([^\]]*))?\]\]/g;
const inlineMatches = [];
let m;
while ((m = inlineRegex.exec(html)) !== null) {
  inlineMatches.push({
    num: parseInt(m[1], 10),
    alt: (m[2] || '').trim(),
    link: (m[3] || '').trim(),
    placeholder: m[0]
  });
}

for (const inline of inlineMatches) {
  const altSlug = slugify(inline.alt) || (keywordSlug + '-' + inline.num);
  specs.push({
    is_featured: false,
    source_filename: inline.num + '.png',
    seo_filename: altSlug + '.png',
    alt_text: inline.alt || (keyword + ' image ' + inline.num),
    link_url: inline.link || 'https://dimag.agency',
    position: inline.num,
    placeholder: inline.placeholder
  });
}

return specs.map(spec => ({
  json: {
    ...spec,
    folder_id: folderId,
    keyword: keyword,
    topic: topic,
    row_number: rowNumber,
    clean_content: html,
    article_title: $json.article_title,
    seo_title: $json.seo_title,
    meta_description: $json.meta_description,
    slug: $json.slug
  }
}));
